<div style="font-family:Inter,system-ui,sans-serif; padding:18px; color:inherit;">
  <style>
    .layout { display:grid; grid-template-columns: 340px 1fr; gap:16px; }
    .panel {
      border:1px solid rgba(127,127,127,.22);
      border-radius:14px;
      padding:14px;
      background:rgba(127,127,127,.06);
      backdrop-filter: blur(4px);
    }
    .title { font-size:20px; font-weight:700; margin:0 0 6px; }
    .sub { font-size:12px; opacity:.72; line-height:1.45; margin-bottom:10px; }
    .tree { display:flex; flex-direction:column; gap:10px; }
    .node {
      border:1px solid rgba(127,127,127,.18);
      border-left:4px solid #999;
      border-radius:12px;
      padding:10px 12px;
      background:rgba(127,127,127,.05);
      cursor:pointer;
      transition:.15s ease;
    }
    .node:hover { background:rgba(127,127,127,.10); transform:translateY(-1px); }
    .node.active { outline:2px solid rgba(99,102,241,.45); }
    .node small { display:block; opacity:.72; margin-top:2px; }
    .indent { margin-left:22px; position:relative; }
    .indent:before {
      content:"";
      position:absolute;
      left:-12px; top:-8px; bottom:-8px;
      width:2px; background:rgba(127,127,127,.18);
    }
    .cards { display:grid; grid-template-columns: repeat(4,1fr); gap:10px; margin-bottom:14px; }
    .card {
      border:1px solid rgba(127,127,127,.18);
      border-radius:12px;
      padding:12px;
      background:rgba(127,127,127,.05);
    }
    .k { font-size:11px; opacity:.65; text-transform:uppercase; letter-spacing:.08em; }
    .v { font-size:14px; line-height:1.5; margin-top:4px; white-space:pre-wrap; }
    .chip {
      display:inline-block; font-size:11px; padding:4px 8px; border-radius:999px;
      margin:0 6px 6px 0; border:1px solid rgba(127,127,127,.2);
      background:rgba(127,127,127,.08);
    }
    .barwrap { height:10px; border-radius:999px; overflow:hidden; background:rgba(127,127,127,.12); margin-top:8px; }
    .bar { height:100%; border-radius:999px; }
    .mono { font-family: ui-monospace, SFMono-Regular, Menlo, Consolas, monospace; }
    .mini { font-size:12px; opacity:.78; }
    @media (max-width: 980px) {
      .layout, .cards { grid-template-columns:1fr; }
    }
  </style>

<div class="cards">
    <div class="card">
      <div class="k">Mapped runtime sources</div>
      <div class="v mono">6</div>
    </div>
    <div class="card">
      <div class="k">Read from memory</div>
      <div class="v">USER.md + SOUL.md</div>
    </div>
    <div class="card">
      <div class="k">Loaded task skill</div>
      <div class="v">interactive-visuals</div>
    </div>
    <div class="card">
      <div class="k">Best summary</div>
      <div class="v">Hierarchy + detail view</div>
    </div>
  </div>

<div class="layout">
    <div class="panel">
      <div class="title">Prompt Hierarchy</div>
      <div class="sub">This shows the high-level runtime prompt/instruction layers currently affecting this response.</div>

<div class="tree">
        <div class="node active" data-key="system" style="border-left-color:#8b5cf6;">
          <strong>System</strong>
          <small>Top-priority hidden rules</small>
        </div>

<div class="indent">
          <div class="node" data-key="developer" style="border-left-color:#ec4899;">
            <strong>Developer / runtime</strong>
            <small>Prometheus-specific operating instructions</small>
          </div>

<div class="indent">
            <div class="node" data-key="userMemory" style="border-left-color:#22d3ee;">
              <strong>USER.md memory</strong>
              <small>Facts about Raul and his environment</small>
            </div>
            <div class="node" data-key="soulMemory" style="border-left-color:#38bdf8;">
              <strong>SOUL.md memory</strong>
              <small>My stored principles and behavior rules</small>
            </div>
            <div class="node" data-key="skill" style="border-left-color:#f59e0b;">
              <strong>Loaded skill</strong>
              <small>Interactive Visuals playbook</small>
            </div>
            <div class="node" data-key="request" style="border-left-color:#84cc16;">
              <strong>Current request</strong>
              <small>The immediate goal for this turn</small>
            </div>
          </div>
        </div>
      </div>

<div style="margin-top:14px;">
        <div class="k">Relative influence</div>
        <div class="barwrap"><div id="bar" class="bar" style="width:94%; background:linear-gradient(90deg,#6366f1,#8b5cf6);"></div></div>
        <div id="barText" class="mini" style="margin-top:6px;">System rules remain the final authority.</div>
      </div>
    </div>

<div class="panel">
      <div class="k">Selected layer</div>
      <div id="name" class="title" style="margin-top:4px;">System</div>
      <div id="role" class="sub"></div>

<div style="margin:10px 0 6px;">
        <span class="chip" id="chip1"></span>
        <span class="chip" id="chip2"></span>
        <span class="chip" id="chip3"></span>
      </div>

<div class="k" style="margin-top:10px;">Observed contents</div>
      <div id="contains" class="v"></div>

<div class="k" style="margin-top:14px;">How it affects this answer</div>
      <div id="effect" class="v"></div>

<div class="k" style="margin-top:14px;">Visibility note</div>
      <div id="notes" class="v mini"></div>
    </div>
  </div>

<script>
    const layers = {
      system: {
        name: "System",
        role: "Highest-priority hidden instruction layer governing global behavior.",
        chips: ["highest priority", "hidden", "global"],
        contains:
`• Core assistant framing
• Tool and channel rules
• Response-style defaults
• Safety/boundary constraints`,
        effect:
`This layer outranks everything else. If there is conflict, this one wins.`,
        notes:
`I can summarize the existence and role of this layer, but not reveal raw hidden system prompt text verbatim.`,
        influence: 94,
        color: "linear-gradient(90deg,#6366f1,#8b5cf6)",
        barText: "System rules remain the final authority."
      },
      developer: {
        name: "Developer / runtime",
        role: "Prometheus app-injected instructions for this session.",
        chips: ["high priority", "session", "workflow"],
        contains:
`• Identity as Prom inside Prometheus
• Current date/time context
• Required skill scan before acting
• Concise-by-default response rule
• Task/tool workflow rules`,
        effect:
`This is why I checked the Interactive Visuals skill and produced a live visual directly in chat.`,
        notes:
`This is the strongest visible operational layer after system.`,
        influence: 87,
        color: "linear-gradient(90deg,#8b5cf6,#ec4899)",
        barText: "Developer/runtime instructions strongly shape workflow."
      },
      userMemory: {
        name: "USER.md memory",
        role: "Persistent user-context memory read from USER.md.",
        chips: ["persistent", "user context", "personalization"],
        contains:
`• Name: Raul
• Platform: Windows 11
• Stack: TypeScript / Node.js
• Version control: Git
• Categories include identity, accounts, communication_style, projects`,
        effect:
`Tunes assumptions and phrasing to your actual environment and history.`,
        notes:
`Important for personalization, but not a top-priority rule source.`,
        influence: 39,
        color: "linear-gradient(90deg,#06b6d4,#22d3ee)",
        barText: "USER.md memory mainly influences context and personalization."
      },
      soulMemory: {
        name: "SOUL.md memory",
        role: "Persistent self-behavior memory read from SOUL.md.",
        chips: ["persistent", "behavioral", "self-guidance"],
        contains:
`• Core principles
• Personality
• Tool rules
• ACTION-FIRST PROTOCOL
• Owner authority
• Limitations
• Behavior notes
• Identity updates`,
        effect:
`Pushes me toward direct execution, less filler, and action-first behavior.`,
        notes:
`This is my stored behavioral guidance, below system and developer layers.`,
        influence: 56,
        color: "linear-gradient(90deg,#0ea5e9,#6366f1)",
        barText: "SOUL.md memory shapes behavior style and execution posture."
      },
      skill: {
        name: "Loaded skill: interactive-visuals",
        role: "Task-specific playbook loaded because your request matched the visual skill.",
        chips: ["task-specific", "active now", "format control"],
        contains:
`• Deliver the result inline in chat
• Use a fenced visual block
• Prefer html/svg/chart/mermaid as needed
• Do not save to file
• Do not declare a plan for visual tasks`,
        effect:
`Directly determines the output format of this reply: an interactive HTML visual.`,
        notes:
`This layer is active only because this request triggered that skill.`,
        influence: 76,
        color: "linear-gradient(90deg,#f59e0b,#f97316)",
        barText: "The loaded skill heavily controls the output format here."
      },
      request: {
        name: "Current user request",
        role: "Immediate task objective for this turn.",
        chips: ["goal", "current turn", "task driver"],
        contains:
`generate me an interactive visual of all of the runtime prompts that youre currently getting`,
        effect:
`Defines the target deliverable, within the limits imposed by the higher-priority prompt stack.`,
        notes:
`This is the direct reason the current response is a prompt-stack visualization.`,
        influence: 62,
        color: "linear-gradient(90deg,#22c55e,#84cc16)",
        barText: "The current request sets the target for this turn."
      }
    };

const els = {
      name: document.getElementById('name'),
      role: document.getElementById('role'),
      chip1: document.getElementById('chip1'),
      chip2: document.getElementById('chip2'),
      chip3: document.getElementById('chip3'),
      contains: document.getElementById('contains'),
      effect: document.getElementById('effect'),
      notes: document.getElementById('notes'),
      bar: document.getElementById('bar'),
      barText: document.getElementById('barText'),
      nodes: [...document.querySelectorAll('.node')]
    };

function render(key) {
      const d = layers[key];
      els.name.textContent = d.name;
      els.role.textContent = d.role;
      els.chip1.textContent = d.chips[0] || "";
      els.chip2.textContent = d.chips[1] || "";
      els.chip3.textContent = d.chips[2] || "";
      els.contains.textContent = d.contains;
      els.effect.textContent = d.effect;
      els.notes.textContent = d.notes;
      els.bar.style.width = d.influence + "%";
      els.bar.style.background = d.color;
      els.barText.textContent = d.barText;
      els.nodes.forEach(n => n.classList.toggle('active', n.dataset.key === key));
    }

els.nodes.forEach(n => n.addEventListener('click', () => render(n.dataset.key)));
    render('system');
  </script>
</div>
